#include <stdio.h>
int main() {
    int T, N, M, Q, L, R, i, j, k;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int P[N][M];
        for (i = 0; i < N; i++) {
            for (j = 0; j < M; j++) {
                scanf("%d", &P[i][j]);
            }
        }
        scanf("%d", &Q);
        while (Q--) {
            scanf("%d %d", &L, &R);
            int B[M];
            for (i = 0; i < M; i++) {
                B[i] = i + 1;
            }
            for (i = L - 1; i < R; i++) {
                int temp[M];
                for (j = 0; j < M; j++) {
                    temp[j] = B[P[i][j] - 1];
                }
                for (j = 0; j < M; j++) {
                    B[j] = temp[j];
                }
            }
            int sum = 0;
            for (i = 0; i < M; i++) {
                sum += (i + 1) * B[i];
            }
            printf("%d\n", sum);
        }
    }
    return 0;
}

