import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] P = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    P[i][j] = sc.nextInt();
                }
            }
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int[] B = new int[M];
                for (int i = 0; i < M; i++) {
                    B[i] = i + 1;
                }
                for (int i = L - 1; i < R; i++) {
                    int[] temp = new int[M];
                    for (int j = 0; j < M; j++) {
                        temp[j] = B[P[i][j] - 1];
                    }
                    for (int j = 0; j < M; j++) {
                        B[j] = temp[j];
                    }
                }
                int sum = 0;
                for (int i = 0; i < M; i++) {
                    sum += (i + 1) * B[i];
                }
                System.out.println(sum);
            }
        }
    }
}

