const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++];
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const [N, M] = input().split(' ').map(Number);
    const P = [];
    for (let j = 0; j < N; j++) {
        P.push(input().split(' ').map(Number));
    }
    const Q = parseInt(input());
    for (let j = 0; j < Q; j++) {
        const [L, R] = input().split(' ').map(Number);
        const B = Array(M).fill(0).map((_, i) => i + 1);
        for (let k = L - 1; k < R; k++) {
            const temp = [];
            for (let l = 0; l < M; l++) {
                temp.push(B[P[k][l] - 1]);
            }
            B.splice(0, M, ...temp);
        }
        let sum = 0;
        for (let k = 0; k < M; k++) {
            sum += (k + 1) * B[k];
        }
        console.log(sum);
    }
}
